 

"use strict";

//-----------------------------------------------------------------------------


 
class MergeStrategy {

     
    static overwrite(value1, value2) {
        return value2;
    }

     
    static replace(value1, value2) {
        if (typeof value2 !== "undefined") {
            return value2;
        }

        return value1;
    }

     
    static assign(value1, value2) {
        return Object.assign({}, value1, value2);
    }
}

exports.MergeStrategy = MergeStrategy;
